function GoalIcon({ value, size = 48 }) {
  const icon = GOAL_ICONS[value];
  if (!icon) return null;
  // Re-render the icon SVG with overridden width/height
  const svgProps = { ...icon.props, width: size, height: size };
  return <icon.type {...svgProps} />;
}

